GameArea = class()

function GameArea:ctor(area)
    self.startPos = area.startPos
    self.endPos = area.endPos
    self.waitShrinkTime = tonumber(area.waitShrinkTime)
    self.shrinkTime = tonumber(area.shrinkTime)
    self.waitCreatTime = tonumber(area.waitCreatTime) or 0
    self.moveSpeed = 0
    self.bleedValue = area.bleedValue or GameConfig.initBleedValue
end

function GameArea:setMoveSpeed(speed)
    self.moveSpeed = speed
end

function GameArea:inArea(vec3)
    return vec3.x >= self.startPos.x and vec3.x <= self.endPos.x
            and vec3.y >= self.startPos.y and vec3.y <= self.endPos.y
            and vec3.z >= self.startPos.z and vec3.z <= self.endPos.z
end

function GameArea:getCenter()
    local x = (self.startPos.x + self.endPos.x) / 2
    local y = (self.startPos.y + self.endPos.y) / 2
    local z = (self.startPos.z + self.endPos.z) / 2
    return VectorUtil.newVector3(x, y, z)
end

function GameArea:onAreaMove(spos, epos)
    if self.startPos.x < spos.x then
        self.startPos.x = self.startPos.x + self.moveSpeed
    end

    if self.endPos.x > epos.x then
        self.endPos.x = self.endPos.x - self.moveSpeed
    end

    if self.startPos.z < spos.z then
        self.startPos.z = self.startPos.z+ self.moveSpeed
    end

    if self.endPos.z > epos.z then
        self.endPos.z = self.endPos.z - self.moveSpeed
    end

    if self.startPos.x >= spos.x then
        self.startPos.x = spos.x
    end

    if self.endPos.x <= epos.x then
        self.endPos.x = epos.x
    end

    if self.startPos.z >= spos.z then
        self.startPos.z = spos.z
    end

    if self.endPos.z <= epos.z then
        self.endPos.z = epos.z
    end
end